prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?def ?choreo WHERE {
  ?model a bboExt:Model .
  FILTER(CONTAINS(STR(?model), "4fba0078103d44d9846d4fbec51710cb"))
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    ?def tai:belongsTo ?model .
    OPTIONAL { ?choreo tai:belongsTo ?def . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?mfName ?sourceRef ?targetRef ?messageRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4fba0078103d44d9846d4fbec51710cb" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?mf tai:belongsTo ?choreo .
  ?mf a bboExt:MessageFlow .
  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?messageRef . }
}
LIMIT 25
